public static boolean solve(long[] nums) {
    int n = nums.length;
    for (int p = 1; p < n - 2; p++) {
        for (int q = p + 1; q < n - 1; q++) {
            // Check nums[0..p] is strictly increasing
            boolean firstPart = true;
            for (int i = 1; i <= p; i++) {
                if (nums[i] <= nums[i - 1]) {
                    firstPart = false;
                    break;
                }
            }
            if (!firstPart) {
                continue;
            }

            // Check nums[p..q] is strictly decreasing
            boolean secondPart = true;
            for (int i = p + 1; i <= q; i++) {
                if (nums[i] >= nums[i - 1]) {
                    secondPart = false;
                    break;
                }
            }
            if (!secondPart) {
                continue;
            }

            // Check nums[q..n-1] is strictly increasing
            boolean thirdPart = true;
            for (int i = q + 1; i < n; i++) {
                if (nums[i] <= nums[i - 1]) {
                    thirdPart = false;
                    break;
                }
            }
            if (thirdPart) {
                return true;
            }
        }
    }
    return false;
}
