public static boolean solve(long[] nums) {
    int n = nums.length;
    for (int p = 1; p < n - 1; p++) {
        for (int q = p + 1; q < n - 1; q++) {
            boolean firstIncreasing = true;
            for (int i = 1; i <= p; i++) {
                if (nums[i] <= nums[i - 1]) {
                    firstIncreasing = false;
                    break;
                }
            }
            if (!firstIncreasing) {
                continue;
            }

            boolean middleDecreasing = true;
            for (int i = p + 1; i <= q; i++) {
                if (nums[i] >= nums[i - 1]) {
                    middleDecreasing = false;
                    break;
                }
            }
            if (!middleDecreasing) {
                continue;
            }

            boolean lastIncreasing = true;
            for (int i = q + 1; i < n; i++) {
                if (nums[i] <= nums[i - 1]) {
                    lastIncreasing = false;
                    break;
                }
            }
            if (lastIncreasing) {
                return true;
            }
        }
    }
    return false;
}
